def trouver_creneaux_libres(agenda, duree=60):
    from datetime import datetime, timedelta
    now = datetime.now()
    creneaux = []
    # Simuler des créneaux libres (ex: 7h-8h, 12h-13h, 18h-19h)
    for h in [7, 12, 18]:
        start = now.replace(hour=h, minute=0, second=0, microsecond=0)
        end = start + timedelta(minutes=duree)
        creneaux.append({'start': start.isoformat(), 'end': end.isoformat()})
    return creneaux
